package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair122DifferenceFindingTest {

    private final ClonePair122 subject = new ClonePair122();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{-Double.MAX_VALUE, -1.0, -1.0};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(((Double) values[0]).doubleValue(), ((Double) values[1]).doubleValue(), ((Double) values[2]).doubleValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(((Double) values[0]).doubleValue(), ((Double) values[1]).doubleValue(), ((Double) values[2]).doubleValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Double(-1.7976931348623157E308)",
            null,
            "java.lang.Object[][Double(-1.7976931348623157E308),Double(-1.0),Double(-1.0)]",
            "java.lang.Object[][Double(-1.7976931348623157E308),Double(-1.0),Double(-1.0)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Double(NaN)",
            null,
            "java.lang.Object[][Double(-1.7976931348623157E308),Double(-1.0),Double(-1.0)]",
            "java.lang.Object[][Double(-1.7976931348623157E308),Double(-1.0),Double(-1.0)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
